f5_irule:
when HTTP_REQUEST {
    set lower_uri [string tolower [HTTP::uri]]
    if {[regexp {(<script|%3cscript|javascript:|onerror=|onload=|<img)} $lower_uri]} {
        log local0. "WAF XSS baseline matched for [IP::client_addr] on $lower_uri"
        HTTP::respond 403 content "Request blocked by security policy"
        event disable all
    }
  }
